pub enum SopCacheifCheckgroups {
    OnEveryCook = 0,
    OnUpstreamChange = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopCacheifParmGrouptype {
    Primitives = 0,
    Points = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopCacheifExprCachewhen {
    ExpressionIsTrue = 0,
    ExpressionChanges = 1,
}

